#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    // Parallelise over the outermost loop; each iteration is independent.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Scale the lower‑triangular portion of C by beta.
        double* Ci = C[i].data();            // pointer to row i of C
        for (int j = 0; j <= i; ++j) {
            Ci[j] *= beta;
        }

        // Accumulate alpha * A[i,k] * A[j,k] over k.
        for (int k = 0; k < m; ++k) {
            double aik = A[i][k];            // value reused for all j
            for (int j = 0; j <= i; ++j) {
                Ci[j] += alpha * aik * A[j][k];
            }
        }
    }
}
