/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    // Use raw pointers for fast indexed access
    double * const a = A.data();
    double * const b = B.data();

    // Pre‑compute the reciprocal of 3 to avoid repeated division
    const double inv3 = 1.0/3.0;

    // Use a single loop per time step; inner loops are
    // parallelized and vectorized by the compiler.
    for (int t = 0; t < tsteps; ++t) {
        /* First half–step: compute B from A */
        #pragma omp parallel for schedule(static) simd
        for (int i = 1; i < n - 1; ++i) {
            b[i] = inv3 * (a[i-1] + a[i] + a[i+1]);
        }

        /* Second half–step: compute A from B */
        #pragma omp parallel for schedule(static) simd
        for (int i = 1; i < n - 1; ++i) {
            a[i] = inv3 * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
