void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D vector to a 1‑D array for better cache locality
    int* flat = new int[n * n];
    for (int i = 0; i < n; ++i)
        std::memcpy(flat + i * n, path[i].data(), n * sizeof(int));

    // Core FW loop (k outer – keep sequential, i parallel)
    for (int k = 0; k < n; ++k) {
        const int* pk = flat + k * n;          // row k
        int*   pk_col = flat + k;              // column k
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int* pi = flat + i * n;            // row i
            int ik = pi[k];                    // path[i][k]
            for (int j = 0; j < n; ++j) {
                int val = ik + pk[j];
                if (pi[j] > val) pi[j] = val;
            }
        }
    }

    // Copy back the result
    for (int i = 0; i < n; ++i)
        std::memcpy(path[i].data(), flat + i * n, n * sizeof(int));

    delete[] flat;
}
