/* 2‑D Seidel kernel, timed in full.
 * Exact semantics are preserved.            */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A) {

    const double inv9 = 1.0 / 9.0;

    /* Main time loop.  All work is done inside the
     * parallel region below to keep the CPU cores busy.
     */
    for (int t = 0; t < tsteps; ++t) {

#pragma omp parallel for schedule(static) collapse(2)
        for (int i = 1; i <= n - 2; ++i) {
            /* Local references to the neighbouring rows
             * to avoid repeated index calculations.          */
            std::vector<double>& prev = A[i - 1];
            std::vector<double>& cur  = A[i];
            std::vector<double>& next = A[i + 1];

            for (int j = 1; j <= n - 2; ++j) {
                cur[j] = (prev[j - 1] + prev[j] + prev[j + 1] +
                          cur[j - 1]  + cur[j]  + cur[j + 1] +
                          next[j - 1] + next[j] + next[j + 1]) * inv9;
            }
        }
    }
}
