    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Ai = A[i].data();   /* pointer to the i‑th row of A   */
        double *Bi = B[i].data();   /* pointer to the i‑th row of B   */
        double *xv = x.data();      /* pointer to the input vector   */
        double sumA = 0.0;
        double sumB = 0.0;

        /* Inner summation */
        for (int j = 0; j < n; ++j) {
            sumA += Ai[j] * xv[j];
            sumB += Bi[j] * xv[j];
        }

        tmp[i] = sumA;                /* store the intermediate result   */
        y[i]   = alpha * sumA + beta * sumB; /* final fused update          */
    }
}
