#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // ---------- 1) Allocate contiguous buffers ----------
    // data_flat: n rows * m cols, row-major
    std::vector<double> data_flat(n * m);
    // copy original data into the flat buffer
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data_flat[i * m + j] = data[i][j];

    // ---------- 2) compute mean -----
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += data_flat[i * m + j];
        mean[j] = sum / n;
    }

    // ---------- 3) subtract mean from data (center data) ----------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        int base = i * m;
        for (int j = 0; j < m; ++j)
            data_flat[base + j] -= mean[j];
    }

    // ---------- 4) compute covariance matrix (upper triangular) ----------
    // We will compute only the upper triangle and mirror it to lower.
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data_flat[k * m + i] * data_flat[k * m + j];
            double val = sum / (n - 1.0);
            cov[i][j] = val;
            cov[j][i] = val;
        }
    }
}
```
