/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /* Form  B := alpha * A^T * B.
       A is MxM,  B is MxN.
       The operation is performed in place and preserves the exact
       numerical result of the reference implementation.   */

    // Parallelise the outer two loops.  Because the inner k-loop
    // accesses only rows with index > i, there are no data races
    // between different (i, j) pairs.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            double val = B[i][j];          // original B[i][j]
            for (int k = i + 1; k < m; ++k) {
                val += A[k][i] * B[k][j];
            }
            B[i][j] = alpha * val;
        }
    }
}
