/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) noexcept
{
    // Prepare a temporary buffer
    std::vector<double> z(n, 0.0);

    // Pointers to underlying data for faster access
    double* rptr = r.data();
    double* yptr = y.data();
    double* zptr = z.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute the sum: sum_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        for (int i = 0; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }

        alpha = -(rptr[k] + sum) / beta;

        // Update z[i] = y[i] + alpha * y[k-i-1]
        for (int i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }

        // Copy updated values back to y
        std::memcpy(yptr, zptr, static_cast<size_t>(k) * sizeof(double));

        // Store the new alpha coefficient
        yptr[k] = alpha;
    }
}
