/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {

    /* The algorithm is unchanged – only data access patterns and
       parallelism are improved for typical x86‑64 hardware. */

    const double a = alpha;
    const double b = beta;

    /* Parallelise the outer loop over the rows of C.
       Each thread works on an independent set of rows. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* restrict cRow = C[i].data();         // pointer to C(i,:)
        const double* restrict a_i   = nullptr;     // used only for
        const double* restrict b_i   = nullptr;     // accessing A[i,:], B[i,:]

        /* Scale the lower triangle of C(i,:) by beta */
        for (int j = 0; j <= i; ++j)
            cRow[j] *= b;

        /* Update using A and B.  The inner loops are deliberately
           written to minimise cache misses: we iterate k first,
           then j, so that the same A[j][k] and B[j][k] values are
           reused as much as possible. */
        for (int k = 0; k < m; ++k) {
            const double* restrict a_k = A.data()->data() + k; // A[ :,k ]
            const double* restrict b_k = B.data()->data() + k; // B[ :,k ]

            double aik = A[i][k] * a;                    // pre‑compute once per i,k
            double bik = B[i][k] * a;                    // pre‑compute once per i,k

            for (int j = 0; j <= i; ++j) {
                // C[i][j] += A[j][k]*alpha*B[i][k] + B[j][k]*alpha*A[i][k];
                cRow[j] += A[j][k] * bik + B[j][k] * aik;
            }
        }
    }
}
