#include <cmath>
#include <vector>
#include <omp.h>

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* --- mean --- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        const std::vector<double> *col = &data[0][j]; // just to silence warnings
        for (int i = 0; i < n; ++i)
            sum += data[i][j];
        mean[j] = sum / n;
    }

    /* --- stddev --- */
    std::vector<double> inv_stddev(m);
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mean[j];
            sum += d * d;
        }
        double val = std::sqrt(sum / n);
        if (val <= eps) val = 1.0;          // avoid divide by zero
        stddev[j] = val;
        inv_stddev[j] = 1.0 / val;
    }

    /* --- normalize data (in-place) --- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n * inv_stddev[j];
        }
    }

    /* --- correlation matrix --- */
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            corr[i][j] = sum;
            corr[j][i] = sum;   // symmetric entry
        }
    }
}
