/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* NOTE: The function signature is preserved to match the harness.
   Implementation focuses on minimal overhead by using direct
   pointer arithmetic on the underlying vector storage. */
void kernel_trisolv(int n,
		    std::vector<std::vector<double>>& L,
		    std::vector<double>& x,
		    std::vector<double>& b) {
    /* A forward‑substitution on a lower‑triangular matrix L
       with unit diagonal (except the given diagonal values).  */
    for (int i = 0; i < n; ++i) {
        double val = b[i];                     // start with RHS entry
        const auto &row = L[i];                // lower‑triangular row
        /* Unroll small j‑loops for better instruction‑level
           concurrency (hand‑tuned for typical matrix sizes). */
        int j = 0;
        for (; j + 7 < i; j += 8) {
            val -= row[j]   * x[j];
            val -= row[j+1] * x[j+1];
            val -= row[j+2] * x[j+2];
            val -= row[j+3] * x[j+3];
            val -= row[j+4] * x[j+4];
            val -= row[j+5] * x[j+5];
            val -= row[j+6] * x[j+6];
            val -= row[j+7] * x[j+7];
        }
        for (; j < i; ++j) {
            val -= row[j] * x[j];
        }
        x[i] = val / row[i];                  // normalize by diagonal
    }
}
