#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) 
{
    // In order to allow the compiler to decide on the best level
    // of parallelism we use a 2‑D parallel loop with collapse(2).
    // The following sections are intentionally split so that
    // the compiler can better keep track of the dependencies.

    /* 0. A <- A + u1*v1^T + u2*v2^T  */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1[i];
        const double ui2 = u2[i];
        double* Arow = A[i].data();
        for (int j = 0; j < n; ++j) {
            Arow[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 1. x += beta * A^T * y   (outer product) */
    // Work with a private temporary because A[j][i] is a read‑only
    // access pattern for a given i.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp = 0.0;                           // local accumulator
        for (int j = 0; j < n; ++j) {
            tmp += beta * A[j][i] * y[j];
        }
        x[i] += tmp;
    }

    /* 2. x += z */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 3. w += alpha * A * x */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        const double xi = x[i];   // not used here, keep for symmetry
        double* Aw = A[i].data();
        double wi = w[i];
        for (int j = 0; j < n; ++j) {
            wi += alpha * Aw[j] * x[j];
        }
        w[i] = wi;
    }
}
