/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Use local pointers for better cache line usage.
       The row vectors are contiguous in the standard container
       representation. */
    double* tmp_ptr  = &tmp[0][0];
    double* A_ptr    = &A[0][0];
    double* B_ptr    = &B[0][0];
    double* C_ptr    = &C[0][0];
    double* D_ptr    = &D[0][0];
    const int A_rows = ni, A_cols = nk;
    const int B_rows = nk, B_cols = nj;
    const int C_rows = nj, C_cols = nl;
    const int D_rows = ni, D_cols = nl;

    /* First tile: tmp[i][j] = alpha * A[i,:] * B[:,j]  */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* tmp_row = tmp_ptr + i * nj;
        const double* A_row = A_ptr + i * nk;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* B_col = B_ptr + j;
            for (int k = 0; k < nk; ++k) {
                sum += alpha * A_row[k] * B_col[k * B_cols];
            }
            tmp_row[j] = sum;
        }
    }

    /* Second tile: D[i][j] = beta * D[i][j] + tmp[i,:] * C[:,j] */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* D_row = D_ptr + i * nl;
        for (int j = 0; j < nl; ++j) {
            double sum = D_row[j] * beta;
            const double* C_col = C_ptr + j;
            const double* tmp_row = tmp_ptr + i * nj;
            for (int k = 0; k < nj; ++k) {
                sum += tmp_row[k] * C_col[k * C_cols];
            }
            D_row[j] = sum;
        }
    }
}
