/* Original signature is preserved. 
   The implementation internally unrolls the 2‑D vector into a 1‑D array
   for cache friendliness and enables OpenMP parallelism. */
void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table) {

    /* Ensure the table is contiguous: flatten into a 1‑D array. */
    std::vector<int> flat_table(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat_table[i * n + j] = table[i][j];

    /* Inlining the match function for speed. */
    auto match = [](int b1, int b2) noexcept {
        return (b1 + b2) == 3 ? 1 : 0;
    };

    /* Parallelise the outer loop over i (which decreases).  Each thread
       works on a contiguous block of i indices, guaranteeing that
       all needed data is already present in cache. */
    #pragma omp parallel for schedule(static)
    for (int i = n - 1; i >= 0; --i) {
        int idx_i = i * n;
        for (int j = i + 1; j < n; ++j) {
            int val = flat_table[idx_i + j];      /* current table[i][j]   */
            if (j - 1 >= 0) {
                int v = flat_table[idx_i + (j - 1)];   /* table[i][j-1] */
                if (v > val) val = v;
            }
            if (i + 1 < n) {
                int v = flat_table[(i + 1) * n + j];   /* table[i+1][j] */
                if (v > val) val = v;
            }
            if (j - 1 >= 0 && i + 1 < n) {
                int inner = flat_table[(i + 1) * n + (j - 1)]; /* table[i+1][j-1] */
                if (i < j - 1) {
                    int cand = inner + match(seq[i], seq[j]);
                    if (cand > val) val = cand;
                } else { /* i == j-1 */
                    if (inner > val) val = inner;
                }
            }
            /* Split into two loops: small k range and the rest */
            for (int k = i + 1; k < j; ++k) {
                int cand = flat_table[idx_i + k] + flat_table[(k + 1) * n + j];
                if (cand > val) val = cand;
            }
            flat_table[idx_i + j] = val;
        }
    }

    /* Copy back to the 2‑D vector. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat_table[i * n + j];
}
