void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // The outer loop cannot be parallelised due to data dependencies
    for (int i = 0; i < n; ++i) {
        // ---------- Inner region: j = 0 .. i-1 ----------
        // Sequential for correctness; each A[i][j] depends on A[i][k] for k< j
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            // Unroll small k loop where possible
            int k = 0;
            for (; k + 3 < j; k += 4) {
                sum += A[i][k]     * A[k][j];
                sum += A[i][k+1]   * A[k+1][j];
                sum += A[i][k+2]   * A[k+2][j];
                sum += A[i][k+3]   * A[k+3][j];
            }
            for (; k < j; ++k) {
                sum += A[i][k] * A[k][j];
            }
            A[i][j] -= sum;
            A[i][j] /= A[j][j];
        }

        // ---------- Outer region: j = i .. n-1 ----------
        // These iterations are independent and can be parallelised
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            int k = 0;
            for (; k + 3 < i; k += 4) {
                sum += A[i][k]     * A[k][j];
                sum += A[i][k+1]   * A[k+1][j];
                sum += A[i][k+2]   * A[k+2][j];
                sum += A[i][k+3]   * A[k+3][j];
