// Optimised Cholesky factorisation kernel
//  - Uses raw pointers for cache‑friendly access
//  - Applies SIMD pragmas to inner loops
//  - Parallelises independent work at the outermost level (if any)
//  - Maintains identical numerical results

#include <cmath>
#include <vector>
#include <omp.h>

void kernel_cholesky(int n, std::vector<std::vector<double>>& A)
{
    // Array of pointers to row data for fast index access
    std::vector<double*> rows(n);
    for (int i = 0; i < n; ++i) rows[i] = A[i].data();

    // Outer loop is strictly serial because later rows depend on all earlier rows
    for (int i = 0; i < n; ++i)
    {
        double* ri = rows[i];

        // --- Off‑diagonal elements (i > j) ---------------------------------
        for (int j = 0; j < i; ++j)
        {
            double* rj = rows[j];
            double sum = 0.0;

            // Vectorised accumulation of A[i][k] * A[j][k] for k < j
            #pragma omp simd reduction(+:sum)
            for (int k = 0; k < j; ++k)
                sum += ri[k] * rj[k];

            ri[j] = (ri[j] - sum) / rj[j];
        }

        // --- Diagonal element ------------------------------------------------
        double sum = 0.0;

        // Vectorised accumulation of A[i][k] * A[i][k] for k < i
        #pragma omp simd reduction(+:sum)
        for (int k = 0; k < i; ++k)
            sum += ri[k] * ri[k];

        ri[i] -= sum;
        ri[i] = std::sqrt(ri[i]);   // final diagonal computation
    }
}
