/* Main computational kernel.  The whole function will be timed,
 * including the call and return.
 *
 *  A is MxM, B is MxN, C is MxN (column‑major layout to mimic
 *  Fortran ordering used in the original code).
 *
 *  C := alpha*A*B + beta*C
 */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* Flatten the 2‑D vectors into 1‑D column‑major arrays to
     * avoid expensive bounds checks and enable better loop
     * transformation.
     */
    const size_t MN = static_cast<size_t>(m) * n;
    const size_t MM = static_cast<size_t>(m) * m;

    std::vector<double> Cf(MN);
    std::vector<double> Af(MM);
    std::vector<double> Bf(MN);

    // copy data into contiguous buffers
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            Cf[i + j * m] = C[i][j];

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < m; ++j)
            Af[i + j * m] = A[i][j];

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            Bf[i + j * m] = B[i][j];

    /* Core computation.  The outer two loops are over i (row of A and C)
     * and j (column of B and C).  The innermost loop over k
     * contributes only to the current row i of C and the previous rows.
     *
     * We parallelise over i since each row is independent once
     * the accumulation from previous rows has been finished.
     */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
    {
        double const Ai_i = Af[i + i * m];   // A[i][i]
        for (int j = 0; j < n; ++j)
        {
            double temp2 = 0.0;
            double Bj = Bf[i + j * m];          // B[i][j]
            for (int k = 0; k < i; ++k)
            {
                double Ak = Af[i + k * m];       // A[i][k]
                double Bk = Bf[k + j * m];      // B[k][j]
                // update the dependent rows (k < i)
                Cf[k + j * m] += alpha * Bj * Ak;
                temp2 += Bk * Ak;
            }
            // update row i
            Cf[i + j * m] = beta * Cf[i + j * m] + alpha * Bj * Ai_i + alpha * temp2;
        }
    }

    /* copy results back into the original 2‑D arrays */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            C[i][j] = Cf[i + j * m];
