    #pragma omp parallel
    #pragma omp single nowait
    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;
        /* Compute norm of column k of A */
        #pragma omp for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            double val = A[i][k];
            nrm += val * val;
        }

        R[k][k] = std::sqrt(nrm);

        /* Normalize to get Q column */
        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            Q[i][k] = A[i][k] / R[k][k];
        }

        /* Update remaining columns */
        #pragma omp for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            /* Compute inner product Q_k^T * A_j */
            #pragma omp for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += Q[i][k] * A[i][j];
            }
            R[k][j] = rkj;

            /* Perform the vector subtraction */
            #pragma omp for schedule(static)
            for (int i = 0; i < m; ++i) {
                A[i][j] -= Q[i][k] * rkj;
