/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/* Based on a Fortran code fragment from Figure 5 of
 * "Automatic Data and Computation Decomposition on Distributed Memory Parallel Computers"
 * by Peizong Lee and Zvi Meir Kedem, TOPLAS, 2002
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX  = 1.0 / static_cast<double>(n);
    const double DY  = 1.0 / static_cast<double>(n);
    const double DT  = 1.0 / static_cast<double>(tsteps);
    const double B1  = 2.0;
    const double B2  = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 * 0.5;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 * 0.5;
    const double e   = 1.0 + mul2;
    const double f   = d;

    /* The two main outer loops (over i) are independent for a given time step,
       so they can be parallelised with OpenMP. The time step loop is left
       sequential because each step depends on the previous one. */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* ----------------------------------------------------------------- */
        /*  first sweep – columns (i) – compute v from u */
        /* ----------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            /* Aliases for the current column */
            double* const v_col   = &v[0][i];
            double* const p_col   = &p[0][i];
            double* const q_col   = &q[0][i];

            /* initialise edges of the column */
            v_col[0]    = 1.0;
            p_col[0]    = 0.0;
            q_col[0]    = v_col[0];

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = a * p_col[j-1] + b;
                p_col[j] = -c / denom;
                q_col[j] = (-d * u[j][i-1] + (1.0 + 2.0*d) * u[j][i]
                            - f * u[j][i+1] - a * q_col[j-1]) / denom;
            }

            v_col[n-1] = 1.0;
            for (int j = n-2; j >= 1; --j)
                v_col[j] = p_col[j] * v_col[j+1] + q_col[j];
        }

        /* ----------------------------------------------------------------- */
        /*  second sweep – rows (i) – compute u from v */
        /* ----------------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            double* const u_row = &u[0][i];
            double* const p_row = &p[0][i];
            double* const q_row = &q[0][i];

            u_row[0]  = 1.0;
            p_row[0]  = 0.0;
            q_row[0]  = u_row[0];

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = d * p_row[j-1] + e;
                p_row[j] = -f / denom;
                q_row[j] = (-a * v[i-1][j] + (1.0 + 2.0*a) * v[i][j]
