        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                flatA[idx(i,j,k)] = A[i][j][k];

    const double coef = 0.125;   // 1/8

    for (int t = 0; t < tsteps; ++t) {
        // First half‑step: A -> B
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n-1; ++i) {
            int base = i * n * n;
            int base_up   = (i+1) * n * n;
            int base_down = (i-1) * n * n;
            for (int j = 1; j < n-1; ++j) {
                int jk = base + j * n;
                int jk_up   = base_up   + j * n;
                int jk_down = base_down + j * n;
                for (int k = 1; k < n-1; ++k) {
                    int id   = jk   + k;
                    int id_up   = jk_up   + k;
                    int id_down = jk_down + k;

                    double val = flatA[id];
                    double res = coef *
                                 (flatA[id_up] - 2.0*val + flatA[id_down]) +
                                 coef *
                                 (flatA[id + n] - 2.0*val + flatA[id - n]) +
                                 coef *
                                 (flatA[id + 1] - 2.0*val + flatA[id - 1]) +
                                 val;
                    flatB[id] = res;
                }
            }
        }

        // Second half‑step: B -> A
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n-1; ++i) {
            int base = i * n * n;
            int base_up   = (i+1) * n * n;
            int base_down = (i-1) * n * n;
            for (int j = 1; j < n-1; ++j) {
                int jk = base + j * n;
                int jk_up   = base_up   + j * n;
                int jk_down = base_down + j * n;
                for (int k = 1; k < n-1; ++k) {
                    int id   = jk   + k;
                    int id_up   = jk_up   + k;
                    int id_down = jk_down + k;

                    double val = flatB[id];
                    double res = coef *
                                 (flatB[id_up] - 2.0*val + flatB[id_down]) +
                                 coef *
                                 (flatB[id + n] - 2.0*val + flatB[id - n]) +
                                 coef *
                                 (flatB[id + 1] - 2.0*val + flatB[id - 1]) +
                                 val;
                    flatA[id] = res;
                }
            }
        }
    }

    // Copy flat array back to the original 3‑D structure
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                A[i][j][k] = flatA[idx(i,j,k)];

    delete[] flatA;
    delete[] flatB;
