/*********************************************************************
 * Optimised Deriche kernel
 *
 * Notes
 * -----
 * * All outer loops are parallelised with OpenMP.
 * * Input / output images are stored as 1‑D contiguous arrays
 *   for maximum cache locality.
 * * All intermediate buffers (y1, y2) are also 1‑D arrays.
 * * Significant register pressure is avoided by using local variables
 *   for recurrence state.
 * * All constants are pre‑computed once.
 *********************************************************************/

#include <cmath>
#include <vector>
#include <cstddef>
#include <omp.h>

/*  Assume the caller provides 1‑D contiguous image buffers in row‑major order.
 *  The signature is kept exactly as requested by the harness. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---------- Flatten 2‑D vectors into 1‑D contiguous buffers ---------- */
    const size_t N = static_cast<size_t>(w) * h;
    std::vector<float> in(N), out(N), tmp1(N), tmp2(N);

    // Helper to index row i, col j
    auto idx = [h](int i, int j){ return static_cast<size_t>(i)*h + j; };

    // Copy input into 1‑D array
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[idx(i,j)] = imgIn[i][j];

    /* ---------- Pre‑compute constants ---------- */
    const float   k  = 1.f - static_cast<float>(std::exp(-alpha)) *
                       (1.f - static_cast<float>(std::exp(-alpha))) /
                       (1.f + 2.f*static_cast<float>(alpha)*static_cast<float>(std::exp(-alpha)) -
                        static_cast<float>(std::exp(2.f*alpha)));

    const float   a1 =  k;
    const float   a2 =  k * static_cast<float>(std::exp(-alpha)) * (static_cast<float>(alpha)-1.f);
    const float   a3 =  k * static_cast<float>(std::exp(-alpha)) * (static_cast<float>(alpha)+1.f);
    const float   a4 = -k * static_cast<float>(std::exp(-2.f*alpha));
    const float   a5 =  k;
    const float   a6 =  k * static_cast<float>(std::exp(-alpha)) * (static_cast<float>(alpha)-1.f);
    const float   a7 =  k * static_cast<float>(std::exp(-alpha)) * (static_cast<float>(alpha)+1.f);
    const float   a8 = -k * static_cast<float>(std::exp(-2.f*alpha));

    const float   b1 = static_cast<float>(std::pow(2.0, -alpha));
    const float   b2 = -static_cast<float>(std::exp(-2.0*alpha));

    const float   c1 = 1.f;
    const float   c2 = 1.f;

    /* ---------- 1st horizontal filtering (forward) ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float ym1 = 0.f, ym2 = 0.f, xm1 = 0.f;
        for (int j = 0; j < h; ++j)
        {
            const float x = in[idx(i,j)];
            const float y = a1*x + a2*xm1 + b1*ym1 + b2*ym2;
            tmp1[idx(i,j)] = y;
            xm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- 2nd horizontal filtering (backward) ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
    {
        float yp1 = 0.f, yp2 = 0.f, xp1 = 0.f, xp2 = 0.f;
        for (int j = h-1; j >= 0; --j)
        {
            const float x = in[idx(i,j)];
            const float y = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            tmp2[idx(i,j)] = y;
            xp2 = xp1;   xp1 = x;   yp2 = yp1;   yp1 = y;
        }
    }

    /* ---------- Sum horizontally filtered results ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i,j)] = c1 * (tmp1[idx(i,j)] + tmp2[idx(i,j)]);

    /* ---------- 1st vertical filtering (forward) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float tm1 = 0.f, ym1 = 0.f, ym2 = 0.f;
        for (int i = 0; i < w; ++i)
        {
            const float x = out[idx(i,j)];
            const float y = a5*x + a6*tm1 + b1*ym1 + b2*ym2;
            tmp1[idx(i,j)] = y;
            tm1 = x;   ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- 2nd vertical filtering (backward) ---------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j)
    {
        float tp1 = 0.f, tp2 = 0.f, yp1 = 0.f, yp2 = 0.f;
        for (int i = w-1; i >= 0; --i)
        {
            const float x = out[idx(i,j)];
            const float y = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            tmp2[idx(i,j)] = y;
            tp2 = tp1;   tp1 = x;   yp2 = yp1;   yp1 = y;
        }
    }

    /* ---------- Final sum and copy back to image buffers ---------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
        {
            const size_t pos = idx(i,j);
            const float val = c2 * (tmp1[pos] + tmp2[pos]);
            imgOut[i][j] = val;
            y1[i][j]    = tmp1[pos];
            y2[i][j]    = tmp2[pos];
        }
}
